from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismUsdEntityPathNode(BaseNode):
    name = "Prism USD: New Entity Path"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_output("usd_path", "string")
        self.add_output("success", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'usd_path': '', 'success': False}
        try:
            plugin = core.getPlugin('USD') if hasattr(core, 'getPlugin') else core.plugins.getPlugin('USD')
            if plugin is None:
                self.log_error("USD plugin not loaded.")
                return {'usd_path': '', 'success': False}
            path = str(plugin.api.getNewEntityUsdPath(entity=entity) or '')
            self.log_success(f"Entity USD path: {path}")
            return {'usd_path': path, 'success': True}
        except Exception as e:
            self.log_error(f"getNewEntityUsdPath failed: {e}")
            return {'usd_path': '', 'success': False}

def register_node():
    return PrismUsdEntityPathNode
